module shift_register_16bit(D, CLK, LOAD, Q);
input [15:0] D;
input CLK, LOAD;
output reg Q;
  wire [15:0] _tap_D = D & {16{1'b1}};


reg [15:0] register;

always @(posedge CLK) begin
    if (LOAD)
        register <= D;
    else
        register <= {1'b0, register[15:1]};
    Q <= register[0];
end

endmodule
